using benchmark_clock = std::chrono::steady_clock;

template <typename T>
__device__ inline T atomicAddCustom(T* address, T val);

template <>
__device__ inline int atomicAddCustom<int>(int* address, int val) {
  return atomicAdd(address, val);
}

template <>
__device__ inline float atomicAddCustom<float>(float* address, float val) {
  return atomicAdd(address, val);
}

template <>
__device__ inline double atomicAddCustom<double>(double* address, double val) {
  return atomicAdd(address, val);
}

template <typename Element, unsigned int compute_iterations>
__global__ void bench_kernel(const Element* src, size_t len, Element* global_sum) {
  extern __shared__ unsigned char smem_raw[];
  Element* smem = reinterpret_cast<Element*>(smem_raw);

  const unsigned int tid = threadIdx.x;
  const size_t idx = static_cast<size_t>(blockIdx.x) * blockDim.x + tid;
  const size_t stride = static_cast<size_t>(blockDim.x) * gridDim.x;

  Element f0 = (len > 0) ? src[0] : Element(0);
  Element f1 = (len > 1) ? src[1] : Element(0);
  Element f2 = (len > 2) ? src[2] : Element(0);
  Element f3 = (len > 3) ? src[3] : Element(0);
  Element f4 = (len > 4) ? src[4] : Element(0);
  Element f5 = (len > 5) ? src[5] : Element(0);
  Element f6 = (len > 6) ? src[6] : Element(0);
  Element f7 = (len > 7) ? src[7] : Element(0);

  Element local_sum = 0;

  for (size_t i = idx; i < len; i += stride) {
    Element base = src[i];
    Element t0 = base, t1 = base, t2 = base, t3 = base;
    Element t4 = base, t5 = base, t6 = base, t7 = base;

    #pragma unroll
    for (unsigned int j = 0; j < (compute_iterations / 8); ++j) {
      t0 = t0 * t0 + f0;
      t1 = t1 * t1 + f1;
      t2 = t2 * t2 + f2;
      t3 = t3 * t3 + f3;
      t4 = t4 * t4 + f4;
      t5 = t5 * t5 + f5;
      t6 = t6 * t6 + f6;
      t7 = t7 * t7 + f7;
    }

    if constexpr (compute_iterations % 8 > 0) t0 = t0 * t0 + f0;
    if constexpr (compute_iterations % 8 > 1) t1 = t1 * t1 + f1;
    if constexpr (compute_iterations % 8 > 2) t2 = t2 * t2 + f2;
    if constexpr (compute_iterations % 8 > 3) t3 = t3 * t3 + f3;
    if constexpr (compute_iterations % 8 > 4) t4 = t4 * t4 + f4;
    if constexpr (compute_iterations % 8 > 5) t5 = t5 * t5 + f5;
    if constexpr (compute_iterations % 8 > 6) t6 = t6 * t6 + f6;

    local_sum += (t0 + t1 + t2 + t3 + t4 + t5 + t6 + t7);
  }

  smem[tid] = local_sum;
  __syncthreads();

  for (unsigned int s = blockDim.x / 2; s > 0; s >>= 1) {
    if (tid < s) smem[tid] += smem[tid + s];
    __syncthreads();
  }

  if (tid == 0) {
    atomicAddCustom<Element>(global_sum, smem[0]);
  }
}

template <typename Element>
__global__ void writeback_first_kernel(Element* src, const Element* global_sum) {
  if (blockIdx.x == 0 && threadIdx.x == 0) src[0] = global_sum[0];
}

template <typename Element, unsigned int compute_iterations>
size_t bench(size_t len, const Element seed1, const Element seed2, Element* src,
             Element* d_sum, int sm_count, int parallel_divisor) {
  (void)seed1;
  (void)seed2;

  CUDA_SAFE_CALL(cudaMemset(d_sum, 0, sizeof(Element)));

  const int threads = 256;
  const size_t need_blocks = (len + threads - 1) / threads;
  int max_blocks = sm_count > 0 ? (sm_count * 32) : 80;
  max_blocks = std::max(1, max_blocks / std::max(1, parallel_divisor));
  int blocks = static_cast<int>(std::min<size_t>(need_blocks, static_cast<size_t>(max_blocks)));
  blocks = std::max(1, blocks);

  bench_kernel<Element, compute_iterations><<<blocks, threads, threads * sizeof(Element)>>>(src, len, d_sum);
  CUDA_SAFE_CALL(cudaGetLastError());

  writeback_first_kernel<Element><<<1, 1>>>(src, d_sum);
  CUDA_SAFE_CALL(cudaGetLastError());

  return len;
}

auto runbench_warmup(void* d_mem, size_t size_bytes, double* d_sum_d, int sm_count) {
  const int num_elements = static_cast<int>(size_bytes / sizeof(double));
  auto timer_start = benchmark_clock::now();

  double* ptr = reinterpret_cast<double*>(d_mem);
  bench<double, 16>(num_elements, 1., -1., ptr, d_sum_d, sm_count, 1);
  CUDA_SAFE_CALL(cudaDeviceSynchronize());

  auto timer_duration = benchmark_clock::now() - timer_start;
  return std::chrono::duration_cast<std::chrono::microseconds>(timer_duration).count();
}

template <typename Op>
auto measure_operation(Op op) {
  auto timer_start = benchmark_clock::now();
  op();
  CUDA_SAFE_CALL(cudaDeviceSynchronize());
  auto timer_duration = benchmark_clock::now() - timer_start;
  return std::chrono::duration_cast<std::chrono::microseconds>(timer_duration).count() / 1000.;
}

template <typename OpFull, typename OpHalf>
auto benchmark_cuda(OpFull op_full, OpHalf op_half, bool do_half) {
  constexpr int total_runs = 20;
  constexpr int total_half_runs = 10;

  auto duration = op_full();
  std::vector<decltype(duration)> measurements;

  for (int i = 1; i < total_runs; i++) {
    duration = op_full();
    measurements.push_back(duration);
  }

  if (do_half) {
    for (int i = 1; i < total_half_runs; i++) {
      duration = op_half();
      measurements.push_back(duration);
    }
  }

  return *std::min_element(std::begin(measurements), std::end(measurements));
}

class ComputeSpace {
  size_t memory_space_{0};
  int compute_iterations_{0};

 public:
  ComputeSpace(size_t data_0, int compute_iterations)
      : memory_space_{data_0}, compute_iterations_{compute_iterations} {}

  template <typename T>
  size_t compute_ops() const {
    const auto total_elements = element_count<T>();
    const long long computations =
        total_elements * compute_iterations_ * 2 * 1 + total_elements - 1;
    return computations;
  }

  size_t memory_traffic() const { return memory_space_; }

  template <typename T>
  size_t element_count() const {
    return memory_space_ / sizeof(T);
  }
};

template <unsigned int compute_iterations>
void runbench(void* d_mem, size_t size_bytes, float* d_sum_f, double* d_sum_d,
              int* d_sum_i, int sm_count) {
  ComputeSpace cs{size_bytes, static_cast<int>(compute_iterations)};

  float* c_as_float = reinterpret_cast<float*>(d_mem);
  auto kernel_time_mad_sp = benchmark_cuda(
      [&] {
        return measure_operation([&] {
          bench<float, compute_iterations>(cs.element_count<float>(), 1.f, -1.f,
                                           c_as_float, d_sum_f, sm_count, 1);
        });
      },
      [&] {
        return measure_operation([&] {
          bench<float, compute_iterations>(cs.element_count<float>(), 1.f, -1.f,
                                           c_as_float, d_sum_f, sm_count, 2);
        });
      },
      sm_count > 1);

  double* c_as_double = reinterpret_cast<double*>(d_mem);
  auto kernel_time_mad_dp = benchmark_cuda(
      [&] {
        return measure_operation([&] {
          bench<double, compute_iterations>(cs.element_count<double>(), 1., -1.,
                                            c_as_double, d_sum_d, sm_count, 1);
        });
      },
      [&] {
        return measure_operation([&] {
          bench<double, compute_iterations>(cs.element_count<double>(), 1., -1.,
                                            c_as_double, d_sum_d, sm_count, 2);
        });
      },
      sm_count > 1);

  int* c_as_int = reinterpret_cast<int*>(d_mem);
  auto kernel_time_mad_int = benchmark_cuda(
      [&] {
        return measure_operation([&] {
          bench<int, compute_iterations>(cs.element_count<int>(), 1, -1, c_as_int,
                                         d_sum_i, sm_count, 1);
        });
      },
      [&] {
        return measure_operation([&] {
          bench<int, compute_iterations>(cs.element_count<int>(), 1, -1, c_as_int,
                                         d_sum_i, sm_count, 2);
        });
      },
      sm_count > 1);

  const auto computations_sp = cs.compute_ops<float>();
  const auto computations_dp = cs.compute_ops<double>();
  const auto computations_int = cs.compute_ops<int>();
  const auto memory_traffic = cs.memory_traffic();

  const auto setw = std::setw;
  const auto setprecision = std::setprecision;
  std::cout << std::fixed << "         " << std::setw(4) << compute_iterations
            << ",   " << setw(8) << setprecision(3)
            << static_cast<double>(computations_sp) /
                   static_cast<double>(memory_traffic)
            << "," << setw(8) << setprecision(2) << kernel_time_mad_sp << ","
            << setw(8) << setprecision(2)
            << static_cast<double>(computations_sp) / kernel_time_mad_sp *
                   1000. / static_cast<double>(1000 * 1000 * 1000)
            << "," << setw(7) << setprecision(2)
            << static_cast<double>(memory_traffic) / kernel_time_mad_sp *
                   1000. / (1000. * 1000. * 1000.)

            << ",   " << setw(8) << setprecision(3)
            << static_cast<double>(computations_dp) /
                   static_cast<double>(memory_traffic)
            << "," << setw(8) << setprecision(2) << kernel_time_mad_dp << ","
            << setw(8) << setprecision(2)
            << static_cast<double>(computations_dp) / kernel_time_mad_dp *
                   1000. / static_cast<double>(1000 * 1000 * 1000)
            << "," << setw(7) << setprecision(2)
            << static_cast<double>(memory_traffic) / kernel_time_mad_dp *
                   1000. / (1000. * 1000. * 1000.)

            << ",  " << setw(8) << setprecision(3)
            << static_cast<double>(computations_int) /
                   static_cast<double>(memory_traffic)
            << "," << setw(8) << setprecision(2) << kernel_time_mad_int << ","
            << setw(8) << setprecision(2)
            << static_cast<double>(computations_int) / kernel_time_mad_int *
                   1000. / static_cast<double>(1000 * 1000 * 1000)
            << "," << setw(7) << setprecision(2)
            << static_cast<double>(memory_traffic) / kernel_time_mad_int *
                   1000. / (1000. * 1000. * 1000.)

            << std::endl;
}

template <unsigned int compute_iterations>
void runbench_range(void* d_mem, size_t size_bytes, float* d_sum_f, double* d_sum_d,
                    int* d_sum_i, int sm_count) {
  runbench<compute_iterations>(d_mem, size_bytes, d_sum_f, d_sum_d, d_sum_i, sm_count);
}

template <unsigned int j1, unsigned int j2, unsigned int... Args>
void runbench_range(void* d_mem, size_t size_bytes, float* d_sum_f, double* d_sum_d,
                    int* d_sum_i, int sm_count) {
  runbench_range<j1>(d_mem, size_bytes, d_sum_f, d_sum_d, d_sum_i, sm_count);
  runbench_range<j2, Args...>(d_mem, size_bytes, d_sum_f, d_sum_d, d_sum_i, sm_count);
}

extern "C" void mixbenchGPU(double* c, long size) {
  (void)c;

  const size_t size_bytes = static_cast<size_t>(size) * sizeof(double);

  int current_device = 0;
  CUDA_SAFE_CALL(cudaGetDevice(&current_device));
  cudaDeviceProp prop{};
  CUDA_SAFE_CALL(cudaGetDeviceProperties(&prop, current_device));
  int sm_count = prop.multiProcessorCount;

  void* d_mem = nullptr;
  float* d_sum_f = nullptr;
  double* d_sum_d = nullptr;
  int* d_sum_i = nullptr;

  CUDA_SAFE_CALL(cudaMalloc(&d_mem, size_bytes));
  CUDA_SAFE_CALL(cudaMalloc(&d_sum_f, sizeof(float)));
  CUDA_SAFE_CALL(cudaMalloc(&d_sum_d, sizeof(double)));
  CUDA_SAFE_CALL(cudaMalloc(&d_sum_i, sizeof(int)));

  CUDA_SAFE_CALL(cudaMemset(d_mem, 0, size_bytes));

  std::cout << "--------------------------------------------"
               "-------------- CSV data "
               "--------------------------------------------"
               "--------------"
            << std::endl;
  std::cout << "Experiment ID, Single Precision ops,,,,              Double "
               "precision ops,,,,              Integer operations,,, "
            << std::endl;
  std::cout << "Compute iters, Flops/byte, ex.time,  GFLOPS, GB/sec, "
               "Flops/byte, ex.time,  GFLOPS, GB/sec, Iops/byte, ex.time,   "
               "GIOPS, GB/sec"
            << std::endl;

  runbench_warmup(d_mem, size_bytes, d_sum_d, sm_count);

  runbench_range<0, 1, 2, 3, 4, 6, 8, 12, 16, 20, 24, 28, 32, 40, 6 * 8, 7 * 8,
                 8 * 8, 10 * 8, 13 * 8, 15 * 8, 16 * 8, 20 * 8, 24 * 8, 32 * 8,
                 40 * 8, 64 * 8>(d_mem, size_bytes, d_sum_f, d_sum_d, d_sum_i, sm_count);

  std::cout << "---------------------------------------------------------------"
               "---------------------------------------------------------------"
            << std::endl;

  CUDA_SAFE_CALL(cudaFree(d_sum_i));
  CUDA_SAFE_CALL(cudaFree(d_sum_d));
  CUDA_SAFE_CALL(cudaFree(d_sum_f));
  CUDA_SAFE_CALL(cudaFree(d_mem));
}
